#include <bits/stdc++.h>
using namespace std;
typedef long long ll;

struct node {
    int next, to, w;
} e[100005];

int n, m, b, cnt = 0;
int f[50005], head[50005];
ll dis[50005];
bool vis[50005];
priority_queue<pair<ll, int>, vector<pair<ll, int> >, greater<pair<ll, int> > > q;

void add(int u, int v, int w) {
    e[++cnt].next = head[u];
    e[cnt].to = v;
    e[cnt].w = w;
    head[u] = cnt;
}

int dijkstra(int c) {
    memset(vis, 0, sizeof(vis));
    memset(dis, 0x3f, sizeof(dis));
    dis[1] = 0;
    q.push({0, 1});
    while (!q.empty()) {
        pair<ll, int> t = q.top();
        q.pop();
        int x = t.second;
        if (vis[x]) continue;
        if (x == n) break;
        vis[x] = true;
        for (int i = head[x]; i != 0; i = e[i].next) {
            int y = e[i].to;
            if (f[y] > c) continue;
            if (dis[y] > dis[x] + e[i].w) {
                dis[y] = dis[x] + e[i].w;
                q.push({dis[y], y});
            }
        }
    }
    return dis[n];
}

int main() {
    cin >> n >> m >> b;
    int l = 0, r = 0;
    for (int i = 1; i <= n; i++) {
        cin >> f[i];
        r = max(f[i], r);
    }
    l = max(f[1], f[n]);
    int x, y, z;
    for (int i = 1; i <= m; i++) {
        cin >> x >> y >> z;
        add(x, y, z);
        add(y, x, z);
    }
    int ans = 0;
    while (l <= r) {
        int m = l + (r - l) / 2;
        if (dijkstra(m) <= b) {
            ans = m;
            r = m - 1;
        }
        else {
            l = m + 1;
        }
    }
    if (dijkstra(ans) > b) {
        cout << "AFK\n";
    }
    else {
        cout << ans << endl;
    }
    return 0;
}
